#include <stdio.h>
#include <time.h>
#include <string.h>

int main() {
    char s_str[6], t_str[6];
    scanf("%5s", s_str);
    scanf("%5s", t_str);

    struct tm s, t;
    memset(&s, 0, sizeof(s));
    memset(&t, 0, sizeof(t));

    strptime(s_str, "%H:%M", &s);
    strptime(t_str, "%H:%M", &t);

    time_t s_time = mktime(&s);
    time_t t_time = mktime(&t);
    double diff = difftime(s_time, t_time);

    int hours = diff / 3600;
    int minutes = (diff - hours * 3600) / 60;

    printf("%02d:%02d", hours, minutes);
    return 0;
}
